ON CONFLICT (name) DO UPDATE SET
    description = COALESCE(EXCLUDED.description, funding_opportunities.description),
    website = COALESCE(EXCLUDED.website, funding_opportunities.website),
    sectors = COALESCE(EXCLUDED.sectors, funding_opportunities.sectors),
    stage = COALESCE(EXCLUDED.stage, funding_opportunities.stage),
    check_size_min = COALESCE(EXCLUDED.check_size_min, funding_opportunities.check_size_min),
    check_size_max = COALESCE(EXCLUDED.check_size_max, funding_opportunities.check_size_max),
    location = COALESCE(EXCLUDED.location, funding_opportunities.location),
    confidence_score = GREATEST(EXCLUDED.confidence_score, COALESCE(funding_opportunities.confidence_score, 0)),
    is_active = true;

-- ===========================================
-- Summary Statistics
-- ===========================================
DO $$
DECLARE
    total_count INTEGER;
    chicago_count INTEGER;
    high_conf_count INTEGER;
    med_conf_count INTEGER;
BEGIN
    SELECT COUNT(*) INTO total_count FROM funding_opportunities WHERE opportunity_type = 'vc';
    SELECT COUNT(*) INTO chicago_count FROM funding_opportunities WHERE opportunity_type = 'vc' AND chicago_focused = true;
    SELECT COUNT(*) INTO high_conf_count FROM funding_opportunities WHERE opportunity_type = 'vc' AND confidence_score >= 90;
    SELECT COUNT(*) INTO med_conf_count FROM funding_opportunities WHERE opportunity_type = 'vc' AND confidence_score >= 70 AND confidence_score < 90;
    
    RAISE NOTICE '';
    RAISE NOTICE '===========================================';
    RAISE NOTICE 'Enriched Investor Migration Complete!';
    RAISE NOTICE '===========================================';
    RAISE NOTICE 'Total VC records: %', total_count;
    RAISE NOTICE 'Chicago-focused: %', chicago_count;
    RAISE NOTICE 'High confidence (90+): %', high_conf_count;
    RAISE NOTICE 'Medium confidence (70-89): %', med_conf_count;
    RAISE NOTICE '===========================================';
END $$;
